// ─── Prepare Doc Content: Parse LLM JSON ───
const llmRaw = $("Generate Tailored Resume").item.json.text || '';
let resumeData = {};

try {
  // Clean markdown blocks if present
  const cleaned = llmRaw.replace(/```json/g, '').replace(/```/g, '').trim();
  resumeData = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse LLM response as JSON: ' + e.message + '\nRaw: ' + llmRaw);
}

const meta = $("Prepare Input").item.json;
const dateStr = new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });

return {
  resumeData,
  recipientEmail: meta.recipientEmail,
  companyName: meta.companyName,
  emailBody: `<p>Hi,</p><p>Your tailored resume for <strong>${meta.companyName}</strong> is attached.</p><p>Best of luck!</p>`,
  subject: `📄 Resume for ${meta.companyName} — ${dateStr}`
};

// ─── PDF Generator v4 — Structured, Professional, Optimized ───
const PDFDocument = require('pdfkit');
const meta = $("Prepare Doc Content").item.json;
const data = meta.resumeData || {};

const pdfBuffer = await new Promise((resolve, reject) => {
  const doc = new PDFDocument({
    size: 'A4',
    margins: { top: 25, bottom: 25, left: 35, right: 35 },
    autoFirstPage: true,
    bufferPages: true
  });
  const chunks = [];
  doc.on('data', c => chunks.push(c));
  doc.on('end', () => resolve(Buffer.concat(chunks)));
  doc.on('error', reject);

  const PW = doc.page.width;
  const ML = 35, MR = 35;
  const L = ML, R = PW - MR, CW = R - L;
  const BLACK = '#000000', DARK_GRAY = '#333333', BLUE = '#0047AB', RULE = '#CCCCCC';

  // ── Helper: Draw Section Header ──
  const drawSectionHeader = (title) => {
    if (doc.y > 750) doc.addPage();
    doc.moveDown(0.4);
    doc.font('Helvetica-Bold').fontSize(10.5).fillColor(BLACK)
       .text(title.toUpperCase(), L, doc.y, { width: CW });
    const ry = doc.y + 1;
    doc.moveTo(L, ry).lineTo(R, ry).lineWidth(0.5).strokeColor(RULE).stroke();
    doc.moveDown(0.25);
  };

  // ── Helper: Draw Bullet ──
  const drawBullet = (text, xOffset = 15) => {
    if (!text) return;
    doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY)
       .text('• ', L + 5, doc.y, { continued: true })
       .text(text, { width: CW - xOffset, lineGap: 1, align: 'justify' });
    doc.moveDown(0.05);
  };

  // ── Helper: Draw Row (Left/Right) ──
  const drawRow = (left, right, isBold = false) => {
    const sy = doc.y;
    doc.font(isBold ? 'Helvetica-Bold' : 'Helvetica').fontSize(9.5).fillColor(BLACK)
       .text(left, L, sy, { width: CW - 100 });
    if (right) {
      doc.font('Helvetica-Oblique').fontSize(8.5).fillColor(DARK_GRAY)
         .text(right, L, sy, { width: CW, align: 'right' });
    }
    doc.moveDown(0.1);
  };

  // ── 1. HEADER ──
  const h = data.header || {};
  doc.font('Helvetica-Bold').fontSize(18).fillColor(BLACK).text(h.name || '', { align: 'center' });
  doc.moveDown(0.1);
  doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY).text(h.contact || '', { align: 'center' });

  if (h.links && h.links.length) {
    doc.moveDown(0.1);
    let currentY = doc.y;
    let currentX = L;
    const totalLinksWidth = h.links.reduce((acc, curve) => acc + doc.widthOfString(curve.label + ' | '), 0);
    let startX = (PW - totalLinksWidth) / 2;
    h.links.forEach((link, idx) => {
      doc.font('Helvetica').fontSize(9).fillColor(BLUE)
         .text(link.label, startX, currentY, { link: link.url, continued: idx < h.links.length - 1 });
      if (idx < h.links.length - 1) {
        doc.fillColor(DARK_GRAY).text(' | ', { continued: true });
      }
      startX += doc.widthOfString(link.label + ' | ');
    });
    doc.text('', { continued: false }).moveDown(0.3);
  }

  // ── 2. SUMMARY ──
  if (data.summary) {
    drawSectionHeader('Professional Summary');
    doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY).text(data.summary, { width: CW, align: 'justify', lineGap: 1.5 });
  }

  // ── 3. SKILLS ──
  if (data.skills && data.skills.length) {
    drawSectionHeader('Technical Skills');
    data.skills.forEach(s => {
      doc.font('Helvetica-Bold').fontSize(9).fillColor(BLACK).text(s.category + ': ', L, doc.y, { continued: true })
         .font('Helvetica').text(s.items.join(', '), { width: CW, lineGap: 1 });
      doc.moveDown(0.05);
    });
  }

  // ── 4. EXPERIENCE ──
  if (data.experience && data.experience.length) {
    drawSectionHeader('Professional Experience');
    data.experience.forEach(exp => {
      drawRow(`${exp.title} | ${exp.company}`, exp.date, true);
      if (exp.bullets) exp.bullets.forEach(b => drawBullet(b));
      doc.moveDown(0.15);
    });
  }

  // ── 5. PROJECTS ──
  if (data.projects && data.projects.length) {
    drawSectionHeader('Projects');
    data.projects.forEach(p => {
      const sy = doc.y;
      doc.font('Helvetica-Bold').fontSize(9.5).fillColor(BLACK).text(p.title, L, sy, { continued: !!p.link });
      if (p.link) {
        const displayUrl = p.link.replace(/^https?:\/\//, '');
        doc.font('Helvetica').fontSize(8.5).fillColor(BLUE).text(` (${displayUrl})`, { link: p.link });
      } else {
        doc.text('');
      }
      if (p.bullets) p.bullets.forEach(b => drawBullet(b));
      doc.moveDown(0.1);
    });
  }

  // ── 6. AWARDS ──
  if (data.awards && data.awards.length) {
    drawSectionHeader('Awards & Recognition');
    data.awards.forEach(a => {
      const sy = doc.y;
      doc.font('Helvetica-Bold').fontSize(9).fillColor(BLACK).text(a.title, L, sy, { continued: !!(a.link || a.description) });
      if (a.link) doc.font('Helvetica').fontSize(8).fillColor(BLUE).text(` (Link)`, { link: a.link, continued: !!a.description });
      if (a.description) doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY).text(` — ${a.description}`, { continued: false });
      else doc.text('');
      doc.moveDown(0.08);
    });
  }

  // ── 7. EDUCATION ──
  if (data.education && data.education.length) {
    drawSectionHeader('Education');
    data.education.forEach(edu => {
      drawRow(`${edu.degree} | ${edu.school}`, edu.date, true);
      if (edu.details) {
        doc.font('Helvetica').fontSize(8.5).fillColor(DARK_GRAY).text(edu.details, L + 10, doc.y, { width: CW - 10 });
      }
      doc.moveDown(0.1);
    });
  }

  doc.end();
});

return {
  json: {
    recipientEmail: meta.recipientEmail,
    subject: meta.subject,
    emailBody: meta.emailBody
  },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName: `Resume_${meta.companyName.replace(/\s+/g, '_')}.pdf`
    }
  }
};
